+export function matchEach<input = unknown, output = symbolsType.unset>(): MatchEach<input, output>;
+export function matchEach(value?: unknown): MatchEach<any, any> {
+  return new MatchEachExpression(value, arguments.length > 0, [] as Operation[]) as any;
+}
+
+class MatchEachExpression<input, output> {
+  constructor(
+    private readonly input: input | undefined,
+    private readonly hasInput: boolean,
+    private readonly operations: readonly Operation[]
+  ) {}
+
+  with(...args: any[]): MatchEachExpression<input, output> {
+    const handler = args[args.length - 1] as Clause['handler'];
+    const patterns: Pattern<any>[] = [args[0]];
+    let predicate: Clause['predicate'];
+    if (args.length === 3 && typeof args[1] === 'function') predicate = args[1];
+    else if (args.length > 2) patterns.push(...args.slice(1, -1));
+    return this.next({ patterns, predicate, handler });
+  }
+
+  when(predicate: Clause['predicate'], handler: Clause['handler']) {
+    return this.next({ patterns: [], predicate, handler });
+  }
+
+  tap(callback: (result: output) => void) {
+    return this.next({ tap: callback as (result: unknown) => void });
+  }
+
+  otherwise(handler: (value: input) => output): output[] {
+    const results = this.evaluate(this.requireInput());
+    return results.length ? results : [handler(this.input as input)];
+  }
